import type { AccountItem, SubAccountItem, AccountTaxItem } from './types'
import { clientStorageKey, getSelectedClientId } from './client-store'

function getAccountKey(): string {
  const cid = getSelectedClientId()
  return cid ? clientStorageKey(cid, 'accounts') : 'bank-statement-account-master'
}

function getSubAccountKey(): string {
  const cid = getSelectedClientId()
  return cid ? clientStorageKey(cid, 'sub-accounts') : 'bank-statement-sub-account-master'
}

// --- 科目マスタ ---

export function loadAccountMaster(): AccountItem[] {
  if (typeof window === 'undefined') return []
  try {
    const stored = localStorage.getItem(getAccountKey())
    if (stored) return JSON.parse(stored)
  } catch { /* ignore */ }
  return []
}

export function saveAccountMaster(items: AccountItem[]): void {
  if (typeof window === 'undefined') return
  localStorage.setItem(getAccountKey(), JSON.stringify(items))
}

/**
 * 科目チェックリストTSV/CSVをパース
 * 列: コード, 正式科目名, 簡略科目名, 連想, ..., 正残区分, BS/PL区分, ...
 */
export function parseAccountMasterFile(text: string): AccountItem[] {
  const lines = text.split(/\r?\n/).filter((line) => line.trim())
  if (lines.length === 0) return []

  const delimiter = detectDelimiter(lines[0])
  const startIndex = isHeaderLine(lines[0], ['コード', '科目', 'code']) ? 1 : 0

  const items: AccountItem[] = []
  for (let i = startIndex; i < lines.length; i++) {
    const cells = splitLine(lines[i], delimiter)
    if (cells.length < 2) continue
    const code = cells[0].trim()
    if (!code || !/^\d+$/.test(code)) continue // コードが数字でない行はスキップ

    items.push({
      code,
      name: cells[1]?.trim() || '',
      shortName: cells[2]?.trim() || cells[1]?.trim() || '',
      association: cells[3]?.trim() || '',
      normalBalance: cells[8]?.trim() || '',
      bsPl: cells[9]?.trim() || '',
    })
  }
  return items
}

// --- 補助科目マスタ ---

export function loadSubAccountMaster(): SubAccountItem[] {
  if (typeof window === 'undefined') return []
  try {
    const stored = localStorage.getItem(getSubAccountKey())
    if (stored) return JSON.parse(stored)
  } catch { /* ignore */ }
  return []
}

export function saveSubAccountMaster(items: SubAccountItem[]): void {
  if (typeof window === 'undefined') return
  localStorage.setItem(getSubAccountKey(), JSON.stringify(items))
}

/**
 * 補助科目チェックリストTSV/CSVをパース
 * 列: 科目ｺｰﾄﾞ, 科目簡略名称, 科目別補助ｺｰﾄﾞ, 正式科目名, 簡略科目名, 連想, ...
 */
export function parseSubAccountMasterFile(text: string): SubAccountItem[] {
  const lines = text.split(/\r?\n/).filter((line) => line.trim())
  if (lines.length === 0) return []

  const delimiter = detectDelimiter(lines[0])
  const startIndex = isHeaderLine(lines[0], ['科目', 'ｺｰﾄﾞ', '補助', 'code']) ? 1 : 0

  const items: SubAccountItem[] = []
  for (let i = startIndex; i < lines.length; i++) {
    const cells = splitLine(lines[i], delimiter)
    if (cells.length < 4) continue
    const parentCode = cells[0].trim()
    if (!parentCode || !/^\d+$/.test(parentCode)) continue

    items.push({
      parentCode,
      parentName: cells[1]?.trim() || '',
      subCode: cells[2]?.trim() || '0',
      name: cells[3]?.trim() || '',
      shortName: cells[4]?.trim() || cells[3]?.trim() || '',
      association: cells[5]?.trim() || '',
    })
  }
  return items
}

// --- 検索 ---

export function searchAccounts(master: AccountItem[], query: string): AccountItem[] {
  if (!query) return master.slice(0, 20)
  const q = query.toLowerCase()
  return master
    .filter((item) =>
      item.code.includes(q) ||
      item.name.toLowerCase().includes(q) ||
      item.shortName.toLowerCase().includes(q) ||
      (item.association || '').toLowerCase().includes(q),
    )
    .slice(0, 15)
}

export function findAccountByCode(master: AccountItem[], code: string): AccountItem | undefined {
  return master.find((item) => item.code === code)
}

export function getSubAccountsForCode(subMaster: SubAccountItem[], parentCode: string): SubAccountItem[] {
  return subMaster.filter((item) => item.parentCode === parentCode)
}

// --- ユーティリティ ---

function detectDelimiter(line: string): string {
  const tabCount = (line.match(/\t/g) || []).length
  const commaCount = (line.match(/,/g) || []).length
  return tabCount >= commaCount ? '\t' : ','
}

function splitLine(line: string, delimiter: string): string[] {
  if (delimiter === '\t') return line.split('\t')
  // CSV: ダブルクォート対応
  const cells: string[] = []
  let current = ''
  let inQuotes = false
  for (let i = 0; i < line.length; i++) {
    const ch = line[i]
    if (inQuotes) {
      if (ch === '"' && line[i + 1] === '"') { current += '"'; i++ }
      else if (ch === '"') inQuotes = false
      else current += ch
    } else {
      if (ch === '"') inQuotes = true
      else if (ch === ',') { cells.push(current); current = '' }
      else current += ch
    }
  }
  cells.push(current)
  return cells
}

function isHeaderLine(line: string, keywords: string[]): boolean {
  const lower = line.toLowerCase()
  return keywords.some((k) => lower.includes(k.toLowerCase()))
}

// --- 科目別消費税登録マスタ ---

function getAccountTaxKey(): string {
  const cid = getSelectedClientId()
  return cid ? `bs-account-tax-${cid}` : 'bs-account-tax'
}

export function loadAccountTaxMaster(): AccountTaxItem[] {
  if (typeof window === 'undefined') return []
  try {
    const stored = localStorage.getItem(getAccountTaxKey())
    if (stored) return JSON.parse(stored)
  } catch { /* ignore */ }
  return []
}

export function saveAccountTaxMaster(items: AccountTaxItem[]): void {
  if (typeof window === 'undefined') return
  localStorage.setItem(getAccountTaxKey(), JSON.stringify(items))
}

/**
 * 科目別消費税登録チェックリストTSV/CSVをパース
 * 列: A科目別補助区分, B科目コード, C科目名称, D科目区分, E科目名称,
 *     F仕入消費税コード, G仕入消費税名称, H仕入消費税率区分, I仕入消費税率,
 *     J売上消費税コード, K売上消費税名称, L売上消費税率区分, M売上消費税率, N売上消費税率
 */
export function parseAccountTaxMasterFile(text: string): AccountTaxItem[] {
  const lines = text.split(/\r?\n/).filter((line) => line.trim())
  if (lines.length === 0) return []

  const delimiter = detectDelimiter(lines[0])
  const startIndex = isHeaderLine(lines[0], ['科目', 'コード', 'ｺｰﾄﾞ', '消費税']) ? 1 : 0

  const items: AccountTaxItem[] = []
  for (let i = startIndex; i < lines.length; i++) {
    const cells = splitLine(lines[i], delimiter)
    if (cells.length < 7) continue

    const subFlag = cells[0]?.trim() || ''
    const accountCode = cells[1]?.trim() || ''
    const accountName = cells[2]?.trim() || ''
    const categoryCode = cells[3]?.trim() || '0'
    const categoryName = cells[4]?.trim() || ''
    const purchaseTaxCode = cells[5]?.trim() || '0'
    const purchaseTaxName = cells[6]?.trim() || ''
    const purchaseTaxRate = cells[7]?.trim() || ''  // 税率区分（4=10%, 5=8%軽減 等）
    const salesTaxCode = cells[9]?.trim() || '0'
    const salesTaxName = cells[10]?.trim() || ''
    const salesTaxRate = cells[11]?.trim() || ''

    // +マーク行のみが科目の親行（補助科目行はスキップ）
    if (subFlag !== '+' && accountCode && /^\d+$/.test(accountCode)) {
      // 補助科目でない行（subFlagが空 or +）
      items.push({
        accountCode,
        accountName,
        categoryCode,
        categoryName,
        purchaseTaxCode,
        purchaseTaxName,
        purchaseTaxRate,
        salesTaxCode,
        salesTaxName,
        salesTaxRate,
      })
    } else if (subFlag === '+') {
      items.push({
        accountCode,
        accountName,
        categoryCode,
        categoryName,
        purchaseTaxCode,
        purchaseTaxName,
        purchaseTaxRate,
        salesTaxCode,
        salesTaxName,
        salesTaxRate,
      })
    }
  }
  return items
}

/**
 * 科目コードから消費税コードを取得
 * category: 1=売上, 2=仕入 で判定しコードを返す
 */
export function getDefaultTaxCode(
  accountTaxMaster: AccountTaxItem[],
  accountCode: string,
): { taxCode: string; taxName: string; taxRate?: string } | null {
  const item = accountTaxMaster.find((t) => t.accountCode === accountCode)
  if (!item) return null

  if (item.categoryCode === '1') {
    // 売上: 売上消費税コードを使用
    if (item.salesTaxCode && item.salesTaxCode !== '0') {
      return { taxCode: item.salesTaxCode, taxName: item.salesTaxName || '', taxRate: item.salesTaxRate }
    }
  }
  if (item.categoryCode === '2') {
    // 仕入: 仕入消費税コードを使用
    if (item.purchaseTaxCode && item.purchaseTaxCode !== '0') {
      return { taxCode: item.purchaseTaxCode, taxName: item.purchaseTaxName || '', taxRate: item.purchaseTaxRate }
    }
  }

  // 対象外や0の場合はnull
  return null
}

import type { JournalEntry, CreditCardData, CreditCardTransaction } from './types'
import { findPattern, getPatterns } from './pattern-store'

let idCounter = 0
function generateEntryId(): string {
  return `cc-${Date.now()}-${++idCounter}`
}

function formatUsageDate(usageDate: string): string {
  if (!usageDate) return ''
  const m = usageDate.match(/(\d{1,2})-(\d{1,2})$/)
  if (m) return `${parseInt(m[1])}月${parseInt(m[2])}日`
  const m2 = usageDate.match(/(\d{4})-(\d{1,2})-(\d{1,2})/)
  if (m2) return `${parseInt(m2[2])}月${parseInt(m2[3])}日`
  return usageDate
}

export function creditCardToEntries(
  data: CreditCardData,
  creditCardAccountCode: string,
  creditCardAccountName: string,
  creditCardSubCode?: string,
  creditCardSubName?: string,
): JournalEntry[] {
  const patterns = getPatterns()

  return data.transactions.map((tx) => {
    const amount = Math.abs(tx.amount)
    const isRefund = tx.amount < 0
    const descBase = tx.storeName || ''
    let description = descBase.slice(0, 40)
    const usageDateStr = tx.usageDate.replace(/-/g, '')
    // パターン学習用: 日付部分を除去（毎月変わるためパターンマッチの邪魔になる）
    const storeNameForPattern = stripDateFromDescription(descBase)

    const pattern = findPattern(patterns, storeNameForPattern, amount, creditCardAccountCode)

    let expenseCode = ''
    let expenseName = ''
    let expenseSubCode = ''
    let expenseSubName = ''
    let taxCode = ''
    let taxCategory = ''
    let taxRate = ''
    let businessType = ''
    let patternId: string | null = null

    if (pattern) {
      const line = pattern.lines[0]
      if (line) {
        if (line.debitCode !== creditCardAccountCode) {
          expenseCode = line.debitCode
          expenseName = line.debitName
          expenseSubCode = line.debitSubCode || ''
          expenseSubName = line.debitSubName || ''
        } else if (line.creditCode !== creditCardAccountCode) {
          expenseCode = line.creditCode
          expenseName = line.creditName
          expenseSubCode = line.creditSubCode || ''
          expenseSubName = line.creditSubName || ''
        }
        taxCode = line.taxCode || ''
        taxCategory = line.taxCategory || ''
        taxRate = line.taxRate || ''
        businessType = line.businessType || ''
      }
      patternId = pattern.id

      // 変換後摘要を適用（通帳・現金出納帳の journal-mapper と同じ挙動）
      if (pattern.convertedDescription) {
        if (pattern.matchType === 'exact' || pattern.replaceEntireDescription) {
          description = pattern.convertedDescription.slice(0, 40)
        } else {
          const mt = pattern.matchText || pattern.keyword
          description = descBase.replace(mt, pattern.convertedDescription).slice(0, 40)
        }
      } else if (pattern.matchType === 'exact' && line?.description) {
        // 完全一致で変換後摘要なし → パターンの摘要を使用
        description = line.description.slice(0, 40)
      }
      // 部分一致で変換後摘要なし → 元の摘要をそのまま保持
    }

    // マイナス金額（返品・キャンセル）→ 貸借逆転
    // 消費税CDは常に設定（返品でも課税仕入のまま）
    const entry: JournalEntry = {
      id: generateEntryId(),
      transactionId: null,
      date: usageDateStr,
      debitCode: isRefund ? creditCardAccountCode : expenseCode,
      debitName: isRefund ? creditCardAccountName : expenseName,
      debitSubCode: isRefund ? (creditCardSubCode || '') : expenseSubCode,
      debitSubName: isRefund ? (creditCardSubName || '') : expenseSubName,
      debitTaxType: taxCategory,
      debitIndustry: '',
      debitTaxInclude: '',
      debitAmount: amount,
      debitTaxAmount: 0,
      debitTaxCode: taxCode,
      debitTaxRate: taxRate || (taxCode ? '4' : ''),
      debitBusinessType: businessType,
      creditCode: isRefund ? expenseCode : creditCardAccountCode,
      creditName: isRefund ? expenseName : creditCardAccountName,
      creditSubCode: isRefund ? expenseSubCode : (creditCardSubCode || ''),
      creditSubName: isRefund ? expenseSubName : (creditCardSubName || ''),
      creditTaxType: '',
      creditIndustry: '',
      creditTaxInclude: '',
      creditAmount: amount,
      creditTaxAmount: 0,
      creditTaxCode: '',
      creditTaxRate: '',
      creditBusinessType: '',
      description,
      originalDescription: storeNameForPattern,
      patternId,
      isCompound: false,
      parentId: null,
    }
    return entry
  })
}

/**
 * 利用内容から日付部分を除去してパターン学習キーを生成
 * 例:
 *   "Ｂｉｚ月額料金　１２月　１ＩＤ" → "Ｂｉｚ月額料金　１ＩＤ"
 *   "東京電力 電気料金等 ０７年０３月分" → "東京電力 電気料金等"
 *   "〇〇 2025年4月分" → "〇〇"
 */
function stripDateFromDescription(desc: string): string {
  return desc
    // "07年03月分" "2025年4月分" "０７年０３月分" 等
    .replace(/[０-９0-9]{2,4}年[０-９0-9]{1,2}月分?/g, '')
    // "12月" "１２月" 等（単独の月表記）
    .replace(/[０-９0-9]{1,2}月/g, '')
    // "2025/4" "2025/04" 等
    .replace(/[0-9]{4}\/[0-9]{1,2}/g, '')
    // 余分なスペースを整理
    .replace(/[\s　]+/g, ' ')
    .trim()
}

// 除外キーワード（これらを含む行は解析対象外）
const EXCLUDE_KEYWORDS = ['前回分口座振替金額', '口座振替', '繰越残高', '前回請求額', 'ご利用可能額']

/**
 * クレジットカード CSV/Excel をパースして CreditCardData に変換
 */
export async function parseCreditCardCsv(file: File): Promise<CreditCardData | null> {
  const fileName = file.name.toLowerCase()
  let rows: string[][]

  if (fileName.endsWith('.csv')) {
    const buffer = await file.arrayBuffer()
    const text = decodeCsvText(buffer)
    rows = parseCsvText(text)
  } else {
    const XLSX = await import('xlsx')
    const buffer = await file.arrayBuffer()
    const wb = XLSX.read(buffer, { type: 'array' })
    const sheet = wb.Sheets[wb.SheetNames[0]]
    if (!sheet) return null
    rows = XLSX.utils.sheet_to_json<string[]>(sheet, { header: 1, defval: '' })
      .map((r) => r.map((c) => String(c).trim()))
      .filter((r) => r.some((c) => c))
  }

  if (rows.length < 2) return null

  // ヘッダ行を検出
  let headerRow = -1
  let dateCol = -1
  let descCol = -1
  let amountCol = -1

  const DATE_KW = ['ご利用日', '利用日', '取引日', '日付', 'ご利用年月日', '利用年月日', '年月日', 'ご利用日付']
  const DESC_KW = ['ご利用内容', '利用内容', '利用先', '利用店名', '加盟店', '店名', '摘要', '内容', 'ご利用先']
  const AMT_KW = ['ご利用額', '利用額', '金額', '利用金額', 'ご利用金額', '請求金額', 'お支払金額', '支払金額']

  for (let i = 0; i < Math.min(rows.length, 5); i++) {
    const r = rows[i]
    let dCol = -1, dsCol = -1, aCol = -1
    for (let j = 0; j < r.length; j++) {
      const c = r[j].replace(/[\s　]/g, '')
      if (dCol < 0 && DATE_KW.some((k) => c.includes(k))) dCol = j
      else if (dsCol < 0 && DESC_KW.some((k) => c.includes(k))) dsCol = j
      else if (aCol < 0 && AMT_KW.some((k) => c.includes(k))) aCol = j
    }
    if (dCol >= 0 && aCol >= 0) {
      headerRow = i
      dateCol = dCol
      descCol = dsCol >= 0 ? dsCol : -1
      amountCol = aCol
      break
    }
  }

  if (headerRow < 0 || dateCol < 0 || amountCol < 0) return null

  // データ行をパース
  const transactions: CreditCardTransaction[] = []
  let paymentDate = ''

  for (let i = headerRow + 1; i < rows.length; i++) {
    const r = rows[i]
    const dateText = (r[dateCol] || '').trim()
    if (!dateText) continue

    // 日付パース: 2025/4/17 → 2025-04-17
    const dm = dateText.match(/(\d{4})[/\-.](\d{1,2})[/\-.](\d{1,2})/)
    if (!dm) continue
    const date = `${dm[1]}-${String(dm[2]).padStart(2, '0')}-${String(dm[3]).padStart(2, '0')}`

    const desc = descCol >= 0 ? (r[descCol] || '').trim() : ''
    const amtText = (r[amountCol] || '').replace(/[¥￥,、\s]/g, '')
    const amount = parseInt(amtText, 10)
    if (isNaN(amount)) continue

    // 除外キーワードチェック
    if (EXCLUDE_KEYWORDS.some((kw) => desc.includes(kw))) continue

    if (!paymentDate || date > paymentDate) paymentDate = date

    transactions.push({
      usageDate: date,
      storeName: desc,
      amount: amount,
      memo: amount < 0 ? '返品・取消' : '',
    })
  }

  if (transactions.length === 0) return null

  // 引落日は最も遅い利用日の翌月27日を仮設定（後でユーザーが変更可能）
  const totalAmount = transactions.reduce((s, t) => s + t.amount, 0)

  return {
    paymentDate: paymentDate || new Date().toISOString().slice(0, 10),
    totalAmount,
    cardName: '',
    transactions,
  }
}

// CSV テキストデコード（UTF-8 BOM / UTF-8 / Shift_JIS 自動判定）
function decodeCsvText(buffer: ArrayBuffer): string {
  const bytes = new Uint8Array(buffer)
  if (bytes.length >= 3 && bytes[0] === 0xEF && bytes[1] === 0xBB && bytes[2] === 0xBF) {
    return new TextDecoder('utf-8').decode(bytes.slice(3))
  }
  try {
    return new TextDecoder('utf-8', { fatal: true }).decode(bytes)
  } catch {
    return new TextDecoder('shift_jis').decode(bytes)
  }
}

// CSV パース（ダブルクォート対応）
function parseCsvText(text: string): string[][] {
  const rows: string[][] = []
  let cur: string[] = []
  let field = ''
  let inQuote = false
  for (let i = 0; i < text.length; i++) {
    const c = text[i]
    if (inQuote) {
      if (c === '"') {
        if (text[i + 1] === '"') { field += '"'; i++ }
        else inQuote = false
      } else { field += c }
    } else {
      if (c === '"') inQuote = true
      else if (c === ',') { cur.push(field); field = '' }
      else if (c === '\r') { /* skip */ }
      else if (c === '\n') { cur.push(field); rows.push(cur); cur = []; field = '' }
      else field += c
    }
  }
  if (field.length > 0 || cur.length > 0) { cur.push(field); rows.push(cur) }
  return rows.filter((r) => r.some((c) => c.trim().length > 0))
}

