1	import { parsePdfText, renderPdfPageToImage } from './pdf-text-parser'
2	import { lookupInvoice } from './invoice-registry'
3	import type { StatementPage, BankTransaction } from './types'
4	
5	export interface ReceiptData {
6	  pageIndex: number
7	  date: string
8	  storeName: string
9	  invoiceNumber: string
10	  totalAmount: number
11	  description: string
12	  imageDataUrl?: string
13	}
14	
15	let idCounter = 0
16	function genId(): string {
17	  return `rcpt-${Date.now()}-${++idCounter}`
18	}
19	
20	/**
21	 * テキストPDFのレシートを解析（pdfjs-dist、Gemini不要）
22	 * 各ページ=1枚のレシートとして解析
23	 */
24	export async function parseReceiptTextPdf(
25	  file: File,
26	  onPageParsed?: (data: ReceiptData, pageIndex: number, totalPages: number) => void,
27	): Promise<{ receipts: ReceiptData[]; pages: StatementPage[]; isTextPdf: boolean }> {
