import { parsePdfText, renderPdfPageToImage } from './pdf-text-parser'
import { lookupInvoice } from './invoice-registry'
import type { StatementPage, BankTransaction } from './types'

export interface ReceiptData {
  pageIndex: number
  date: string
  storeName: string
  invoiceNumber: string
  totalAmount: number
  description: string
  imageDataUrl?: string
}

let idCounter = 0
function genId(): string {
  return `rcpt-${Date.now()}-${++idCounter}`
}

/**
 * テキストPDFのレシートを解析（pdfjs-dist、Gemini不要）
 * 各ページ=1枚のレシートとして解析
 */
export async function parseReceiptTextPdf(
  file: File,
  onPageParsed?: (data: ReceiptData, pageIndex: number, totalPages: number) => void,
): Promise<{ receipts: ReceiptData[]; pages: StatementPage[]; isTextPdf: boolean }> {
  const { pages: rawPages, isTextPdf } = await parsePdfText(file)

  if (!isTextPdf) {
    return { receipts: [], pages: [], isTextPdf: false }
  }

  const receipts: ReceiptData[] = []
  const statementPages: StatementPage[] = []

  for (let i = 0; i < rawPages.length; i++) {
    const rows = rawPages[i].rows
    const allText = rows.map((r) => r.cells.join(' ')).join('\n')

    // 各フィールドを抽出
    const invoiceNumber = extractInvoiceNumber(allText)
    const date = extractDate(allText)
    const totalAmount = extractTotalAmount(rows)
    let storeName = extractStoreName(rows)

    // インボイス番号から事業者名を検索
    if (invoiceNumber) {
      const registered = await lookupInvoice(invoiceNumber)
      if (registered) storeName = registered
    }

    const description = storeName || '（店名不明）'

    // 画像生成（1枚ずつ順次表示用）
    const imageDataUrl = await renderPdfPageToImage(file, i + 1, 2)

    const receipt: ReceiptData = {
      pageIndex: i,
      date,
      storeName,
      invoiceNumber,
      totalAmount,
      description,
      imageDataUrl,
    }
    receipts.push(receipt)

    // 取引データとしてページを作成
    const tx: BankTransaction = {
      id: genId(),
      pageIndex: i,
      rowIndex: 0,
      date,
      description,
      deposit: null,
      withdrawal: totalAmount,
      balance: 0,
    }
    statementPages.push({
      pageIndex: i,
      transactions: [tx],
      openingBalance: 0,
      closingBalance: 0,
      isBalanceValid: true,
      balanceDifference: 0,
      imageDataUrl,
    })

    onPageParsed?.(receipt, i, rawPages.length)
  }

  return { receipts, pages: statementPages, isTextPdf: true }
}

function extractInvoiceNumber(text: string): string {
  const m = text.match(/T\d{13}/)
  return m ? m[0] : ''
}

function extractDate(text: string): string {
  // 西暦: 2025/04/01, 2025-04-01, 2025年4月1日
  const m1 = text.match(/(20\d{2})[/\-年](\d{1,2})[/\-月](\d{1,2})/)
  if (m1) {
    return `${m1[1]}-${m1[2].padStart(2, '0')}-${m1[3].padStart(2, '0')}`
  }
  // 和暦: R7.4.1, 令和7年4月1日
  const m2 = text.match(/[令和Rr](\d{1,2})[年./](\d{1,2})[月./](\d{1,2})/)
  if (m2) {
    const year = 2018 + parseInt(m2[1])
    return `${year}-${m2[2].padStart(2, '0')}-${m2[3].padStart(2, '0')}`
  }
  return ''
}

function extractTotalAmount(rows: { cells: string[] }[]): number {
  // 「合計」「お買上」「領収」「税込」の直後の金額を探す
  const keywords = ['合計', 'お買上', '税込合計', '領収', 'ご請求', '小計']
  let bestAmount = 0

  for (const row of rows) {
    const line = row.cells.join(' ')
    for (const kw of keywords) {
      if (line.includes(kw)) {
        const amounts = line.match(/[\d,]+/g)
        if (amounts) {
          for (const a of amounts) {
            const num = parseInt(a.replace(/,/g, ''), 10)
            if (!isNaN(num) && num > bestAmount) bestAmount = num
          }
        }
      }
    }
  }

  // キーワードで見つからない場合、最大の金額を使用
  if (bestAmount === 0) {
    for (const row of rows) {
      for (const cell of row.cells) {
        const m = cell.match(/[\d,]+/)
        if (m) {
          const num = parseInt(m[0].replace(/,/g, ''), 10)
          if (!isNaN(num) && num > bestAmount && num < 10000000) bestAmount = num
        }
      }
    }
  }

  return bestAmount
}

function extractStoreName(rows: { cells: string[] }[]): string {
  // 最初の数行からテキストが最も多い行を店名とする
  for (let i = 0; i < Math.min(rows.length, 5); i++) {
    const text = rows[i].cells.join(' ').trim()
    // 日付や金額だけの行はスキップ
    if (!text || /^\d/.test(text) || text.length < 2) continue
    // 「領収書」「レシート」等のタイトルはスキップ
    if (/^(領収書|レシート|領　収　書)$/.test(text.replace(/\s/g, ''))) continue
    return text
  }
  return ''
}

import type { JournalEntry } from './types'
import { createBlankEntry } from './journal-mapper'

let idCounter = 0
function genId(): string { return `rcp-${Date.now()}-${++idCounter}` }

interface ReceiptData {
  receiptIndex: number
  storeName: string
  receiptDate: string
  mainContent: string
  invoiceNumber?: string
  taxLines: { taxRate: string; netAmount: number; taxAmount: number; totalAmount: number }[]
  pageIndex: number
}

/**
 * レシート・領収書 → 仕訳データに変換
 * 貸方は支払原資（現金等）、借方はユーザーが後で設定
 */
export function receiptToEntries(
  receipts: ReceiptData[],
  creditCode: string,
  creditName: string,
  creditSubCode?: string,
  creditSubName?: string,
): JournalEntry[] {
  const entries: JournalEntry[] = []

  for (const rcp of receipts) {
    const description = `${rcp.storeName}_${rcp.mainContent}`.slice(0, 40)
    const date = rcp.receiptDate.replace(/-/g, '')
    const totalAmount = rcp.taxLines.reduce((s, t) => s + t.totalAmount, 0)
    const hasInvoice = !!rcp.invoiceNumber

    if (rcp.taxLines.length <= 1) {
      const line = rcp.taxLines[0]
      const entry = makeEntry({
        date, debitCode: '', debitName: '', creditCode, creditName,
        creditSubCode, creditSubName,
        amount: totalAmount,
        taxType: line ? getTaxCategory(line.taxRate, hasInvoice) : '',
        taxRate: line?.taxRate, hasInvoice,
        description, originalDescription: `${rcp.storeName}_${rcp.mainContent}`,
      })
      entries.push(entry)
    } else {
      // 複数税率: 997諸口の複合仕訳
      const parentEntry = makeEntry({
        date,
        debitCode: '997', debitName: '諸口',
        creditCode, creditName,
        creditSubCode, creditSubName,
        amount: totalAmount,
        taxType: '',
        description,
        originalDescription: `${rcp.storeName}_${rcp.mainContent}`,
      })
      entries.push(parentEntry)

      for (const line of rcp.taxLines) {
        const childEntry = makeEntry({
          date, debitCode: '', debitName: '',
          creditCode: '997', creditName: '諸口',
          amount: line.totalAmount,
          taxType: getTaxCategory(line.taxRate, hasInvoice),
          taxRate: line.taxRate, hasInvoice,
          description, originalDescription: `${rcp.storeName}_${rcp.mainContent}`,
        })
        childEntry.isCompound = true
        childEntry.parentId = parentEntry.id
        entries.push(childEntry)
      }
    }
  }

  return entries
}

function getTaxCategory(taxRate: string, hasInvoice: boolean): string {
  if (taxRate === '非課税' || taxRate === '0%') return '非仕'
  const rate = taxRate.replace('%', '')
  if (hasInvoice) return `課仕${rate}%`
  return `課仕${rate}%（経過措置）`
}

function taxRateToCode(taxRate: string): string {
  if (taxRate.includes('8')) return '5'
  return '4'
}

function makeEntry(p: {
  date: string; debitCode: string; debitName: string;
  creditCode: string; creditName: string; amount: number;
  creditSubCode?: string; creditSubName?: string;
  taxType: string; taxRate?: string; hasInvoice?: boolean;
  description: string; originalDescription: string;
}): JournalEntry {
  const entry = createBlankEntry()
  entry.id = genId()
  entry.date = p.date
  entry.debitCode = p.debitCode
  entry.debitName = p.debitName
  entry.creditCode = p.creditCode
  entry.creditName = p.creditName
  entry.creditSubCode = p.creditSubCode || ''
  entry.creditSubName = p.creditSubName || ''
  entry.debitAmount = p.amount
  entry.creditAmount = p.amount
  entry.debitTaxType = p.taxType
  entry.debitTaxRate = p.taxRate ? taxRateToCode(p.taxRate) : ''
  entry.debitBusinessType = p.hasInvoice != null ? (p.hasInvoice ? '0' : '1') : '0'
  entry.description = p.description
  entry.originalDescription = p.originalDescription
  return entry
}

  const ccData = await response.json()
  const { creditCardToEntries } = await import('@/lib/bank-statement/credit-card-mapper')
  const entries = creditCardToEntries(ccData, config.creditCode!, config.creditName!, config.creditSubCode, config.creditSubName)

  // PDFページ画像を表示用にセット
  const dummyPages = imageDataUrls.map((url, i) => ({
    pageIndex: i,
    transactions: [],
    openingBalance: 0,
    closingBalance: 0,
    isBalanceValid: true,
    balanceDifference: 0,
    imageDataUrl: url,
  }))
  setPages((prev) => [...prev, ...dummyPages])

  setJournalEntries((prev) => [...prev, ...entries])
  setInfo(`クレジットカード明細: ${entries.length}件の取引を検出（引落日: ${ccData.paymentDate}、引落総額: ¥${(ccData.totalAmount || 0).toLocaleString()}）`)
  clearInterval(progressTimer)
  setLoadingProgress(100)
  setIsLoading(false)
  return
}

if (config.documentType === 'receipt') {
  // レシート・領収書処理: まずテキストPDF解析を試行（無料・高速）
  const { parseReceiptTextPdf } = await import('@/lib/bank-statement/receipt-parser')
  const textResult = await parseReceiptTextPdf(config.file, (receipt, pageIdx, totalPages) => {
    setLoadingProgress(Math.round(15 + 80 * (pageIdx + 1) / totalPages))
  })

  if (textResult.isTextPdf && textResult.receipts.length > 0) {
    // テキストPDF: スクリプトのみで解析完了
    clearInterval(progressTimer)
    setLoadingProgress(100)
    const elapsedSec = ((Date.now() - startTime) / 1000).toFixed(1)
    setParseElapsed(`${elapsedSec}秒`)
    setPages((prev) => [...prev, ...textResult.pages])
    setCurrentPageIndex(0)
    const { receiptToEntries } = await import('@/lib/bank-statement/receipt-mapper')
    const entries = receiptToEntries(textResult.receipts.map((r) => ({
      receiptIndex: r.pageIndex,
      storeName: r.storeName,
      receiptDate: r.date,
      mainContent: r.description,
      invoiceNumber: r.invoiceNumber,
      taxLines: [{ taxRate: '10%', netAmount: 0, taxAmount: 0, totalAmount: r.totalAmount }],
      pageIndex: r.pageIndex,
    })), config.creditCode!, config.creditName!, config.creditSubCode, config.creditSubName)
    setJournalEntries((prev) => [...prev, ...entries])
    setInfo(`${textResult.receipts.length}件のレシートをテキスト解析しました（${elapsedSec}秒）`)
    setIsLoading(false)
    setLoadingProgress(0)
    return
  }

  // 画像PDF: Gemini APIにフォールバック
  const { renderPdfPageToImage, getPdfPageCount } = await import('@/lib/bank-statement/pdf-text-parser')
  const pageCount = await getPdfPageCount(config.file)
  const imageDataUrls: string[] = []
  for (let i = 0; i < pageCount; i++) {
    imageDataUrls.push(await renderPdfPageToImage(config.file, i + 1, 2))
  }

  const response = await fetch('/api/bank-statement/receipt', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ images: imageDataUrls, geminiModel }),
  })
  clearInterval(progressTimer)
  setLoadingProgress(100)

  if (!response.ok) {
    const data = await response.json().catch(() => ({}))
    throw new Error(data.error || 'レシート解析に失敗しました')
  }

  const data = await response.json()
  const receipts = data.receipts || []
  if (receipts.length === 0) throw new Error('レシートデータを抽出できませんでした')

  const statementPages = imageDataUrls.map((url, i) => ({
    pageIndex: i, transactions: [],
    openingBalance: 0, closingBalance: 0, isBalanceValid: true, balanceDifference: 0,
    imageDataUrl: url,
  }))
  setPages((prev) => [...prev, ...statementPages])

  const { receiptToEntries } = await import('@/lib/bank-statement/receipt-mapper')
  const entries = receiptToEntries(receipts, config.creditCode!, config.creditName!, config.creditSubCode, config.creditSubName)
  setJournalEntries((prev) => [...prev, ...entries])
  setInfo(`${receipts.length}件のレシートから${entries.length}件の仕訳を生成しました`)
  setIsLoading(false)
  setLoadingProgress(0)
  return
}

if (config.documentType === 'cash-book') {
  // 現金出納帳処理（通帳と同じロジック）
  const result = await parseFile(config.file, config.accountCode)
  clearInterval(progressTimer)
  setLoadingProgress(100)

  if (result.pdfFile) pdfFileRef.current = result.pdfFile

  if (result.needsColumnMapping && result.rawPages) {
    setRawPages(result.rawPages)
    setPendingSourceType(result.sourceType)
    setPendingImageUrls(result.pageImageUrls || null)
    setShowColumnMapping(true)

    let rows: RawTableRow[] = []
    if (fName.endsWith('.csv')) {
      const { decodeCsvText } = await import('@/lib/bank-statement/transaction-extractor')
      const text = decodeCsvText(await config.file.arrayBuffer())
      rows = text.split(/\r?\n/).filter((l) => l.trim().length > 0)
        .map((l, i) => ({ cells: parseCsvLine(l), rowIndex: i }))
    } else {
      const { parseExcel } = await import('@/lib/bank-statement/excel-parser')
      const sheets = await parseExcel(config.file)
      rows = sheets[0]?.rows || []
    }
    clearInterval(progressTimer)
    setLoadingProgress(0)
    if (rows.length === 0) throw new Error('クレジットカードのファイルから行を読み取れませんでした。')
    setUploadConfig(config)
    uploadConfigRef.current = config
    setCcRawRows(rows)
    setShowCcColumnMapping(true)
    setIsLoading(false)
    return
  }
  const entries = creditCardToEntries(ccData, config.creditCode!, config.creditName!, config.creditSubCode, config.creditSubName)
  // 左側表示用に仮想ページを生成（元データの一覧表示）
  const ccPages: StatementPage[] = [{
    pageIndex: 0,
    transactions: ccData.transactions.map((t, i) => ({
      id: `cc-tx-${Date.now()}-${i}`,
      pageIndex: 0,
      rowIndex: i,
      date: t.usageDate,
      description: t.storeName,
      deposit: t.amount > 0 ? t.amount : null,
      withdrawal: t.amount < 0 ? Math.abs(t.amount) : null,
      balance: 0,
    })),
    openingBalance: 0,
    closingBalance: ccData.totalAmount,
    isBalanceValid: true,
    balanceDifference: 0,
  }]
  setPages((prev) => [...prev, ...ccPages])
  // accountCode にカード科目をセット（残高計算用）
  setUploadConfig({ ...config, accountCode: config.creditCode || '', accountName: config.creditName || '' })
  setJournalEntries((prev) => [...prev, ...entries])
  setInfo(`クレジットカードCSV: ${entries.length}件の取引を検出（引落総額: ¥${ccData.totalAmount.toLocaleString()}）`)
  clearInterval(progressTimer)
  setLoadingProgress(100)
  setIsLoading(false)
  return
}

// クレジットカード PDF 処理（Gemini OCR）
const { renderPdfPageToImage, getPdfPageCount } = await import('@/lib/bank-statement/pdf-text-parser')
const pageCount = await getPdfPageCount(config.file)
const imageDataUrls: string[] = []
for (let i = 0; i < pageCount; i++) {
  imageDataUrls.push(await renderPdfPageToImage(config.file, i + 1, 2))
}

const response = await fetch('/api/bank-statement/credit-card', {
  method: 'POST',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({ images: imageDataUrls, geminiModel }),
})

if (!response.ok) {
