+  // 科目名のフォントカラー判定
+  const acc = accountMaster.find((a) => a.code === code)
+  let nameColor = 'text-gray-800' // BS: 黒
+  if (acc) {
+    if (isPL(acc.bsPl) && acc.normalBalance === '貸方') {
+      nameColor = 'text-blue-600' // PL売上: 青
+    } else if (isPL(acc.bsPl) && acc.normalBalance === '借方') {
